$ok = 0; $fail = @()
foreach ($s in $screens) {
    $dir = Join-Path $base $s.dir
    New-Item -ItemType Directory -Path $dir -Force | Out-Null
    try {
        Invoke-WebRequest -Uri $s.html -OutFile (Join-Path $dir "index.html") -UseBasicParsing
        Invoke-WebRequest -Uri $s.shot -OutFile (Join-Path $dir "screenshot.png") -UseBasicParsing
        $ok++
        Write-Host "OK  $($s.dir)"
    } catch {
        $fail += $s.dir
        Write-Host "FAIL $($s.dir): $($_.Exception.Message)"
    }
}
Write-Host "`n완료: $ok / $($screens.Count)"
if ($fail.Count -gt 0) { Write-Host "실패: $($fail -join ', ')" }
